## Implementation

### App Initialization
```javascript
// main.js - app entry point
async function initializeApp() {
    // 1. Register Service Worker (if not already)
    if ('serviceWorker' in navigator) {
        try {
            const registration = await navigator.serviceWorker.register('./sw.js', {
                scope: './'
            });
            console.log('SW registered:', registration.scope);
        } catch (err) {
            console.warn('SW registration failed:', err);
            // Continue without SW - degraded mode
        }
    }

    // 2. Check COI state
    const coiState = await getCOIState();

    switch (coiState) {
        case 'SW_INSTALLING':
            showInstallingUI();
            // Wait for SW to be ready, then recheck
            navigator.serviceWorker.ready.then(() => {
                setTimeout(initializeApp, 100);
            });
            break;

        case 'NEEDS_RELOAD':
            showReloadRequiredUI();
            break;

        case 'READY':
            hideStatusUI();
            showAuthUI();
            break;
    }
}

// Show reload prompt
function showReloadRequiredUI() {
    const container = document.getElementById('coi-status');
    container.innerHTML = `
        <div class="coi-card needs-reload">
            <div class="coi-icon">🔄</div>
            <h3>One-time Setup Required</h3>
            <p>To enable secure, fast decryption, please reload the page.</p>
            <button id="coi-reload-btn" class="btn-primary">
                Reload Now
            </button>
            <details>
                <summary>Why is this needed?</summary>
                <p>
                    Modern browsers require special security headers for 
                    hardware-accelerated encryption. After reloading, the 
                    archive will decrypt 3-5x faster and support offline access.
                </p>
            </details>
        </div>
    `;
    container.classList.remove('hidden');

    document.getElementById('coi-reload-btn').onclick = () => {
        window.location.reload();
    };
}
```

### Service Worker Update
```javascript
// sw.js - enhanced for COI detection
self.addEventListener('install', (event) => {
    event.waitUntil(
        caches.open(CACHE_NAME)
            .then(cache => cache.addAll(IMMUTABLE_ASSETS))
    );
    self.skipWaiting();
});

self.addEventListener('activate', (event) => {
    event.waitUntil(
        Promise.all([
            self.clients.claim(),
            // Notify clients that SW is now active
            self.clients.matchAll().then(clients => {
                clients.forEach(client => {
                    client.postMessage({ type: 'SW_ACTIVATED' });
                });
            })
        ])
    );
});

// Handle navigation requests with COOP/COEP headers
self.addEventListener('fetch', (event) => {
    const url = new URL(event.request.url);

    if (url.origin !== location.origin) {
        return; // Don't intercept cross-origin
    }

    if (event.request.mode === 'navigate') {
        event.respondWith(
            fetch(event.request).then(response => {
                const headers = new Headers(response.headers);
                headers.set('Cross-Origin-Opener-Policy', 'same-origin');
                headers.set('Cross-Origin-Embedder-Policy', 'require-corp');

                return new Response(response.body, {
                    status: response.status,
                    statusText: response.statusText,
                    headers
                });
            })
        );
        return;
    }

    // Cache-first for other requests
    event.respondWith(
        caches.match(event.request).then(cached => cached || fetch(event.request))
    );
});
```

