## Graceful Degradation

### When COI Not Available
```javascript
// Some browsers/contexts don't support COI
// Provide degraded but functional experience

async function getArgon2Config() {
    if (isSharedArrayBufferAvailable()) {
        return {
            parallelism: 4,  // Use all lanes
            mode: 'wasm-mt', // Multi-threaded WASM
        };
    } else {
        return {
            parallelism: 1,  // Single-threaded fallback
            mode: 'wasm-st', // Single-threaded WASM
        };
    }
}

// Show performance warning in degraded mode
function showDegradedModeWarning() {
    const banner = document.createElement('div');
    banner.className = 'degraded-banner';
    banner.innerHTML = `
        <span>⚠️ Running in compatibility mode - unlock may take longer</span>
        <button onclick="this.parentNode.remove()">✕</button>
    `;
    document.body.prepend(banner);
}
```

