### 2. Entropy-Based Detection
```rust
/// Calculate Shannon entropy of a string
fn shannon_entropy(s: &str) -> f64 {
    let mut freq = [0u32; 256];
    let len = s.len() as f64;

    for byte in s.bytes() {
        freq[byte as usize] += 1;
    }

    freq.iter()
        .filter(|&&c| c > 0)
        .map(|&c| {
            let p = c as f64 / len;
            -p * p.log2()
        })
        .sum()
}

/// Detect high-entropy strings that look like secrets
fn detect_high_entropy_secrets(content: &str, threshold: f64) -> Vec<EntropyMatch> {
    let mut matches = Vec::new();

    // Find potential secret tokens (alphanumeric strings 16+ chars)
    let token_regex = Regex::new(r"\b[a-zA-Z0-9_\-]{16,}\b").unwrap();

    for mat in token_regex.find_iter(content) {
        let token = mat.as_str();
        let entropy = shannon_entropy(token);

        // High entropy + looks like a secret (mixed case, numbers, etc.)
        if entropy >= threshold && looks_like_secret(token) {
            matches.push(EntropyMatch {
                text: token.to_string(),
                entropy,
                start: mat.start(),
                end: mat.end(),
            });
        }
    }

    matches
}

fn looks_like_secret(s: &str) -> bool {
    let has_upper = s.chars().any(|c| c.is_uppercase());
    let has_lower = s.chars().any(|c| c.is_lowercase());
    let has_digit = s.chars().any(|c| c.is_ascii_digit());

    // Secret-like: mixed case + digits, or all hex, etc.
    (has_upper && has_lower && has_digit) ||
    s.chars().all(|c| c.is_ascii_hexdigit()) && s.len() >= 32
}
```

