### 4. Path Hashing (Stealth Mode)
```rust
fn hash_path(path: &Path) -> String {
    use sha2::{Sha256, Digest};

    let mut hasher = Sha256::new();
    hasher.update(path.to_string_lossy().as_bytes());
    let result = hasher.finalize();

    // Use first 16 chars of hex for shorter identifiers
    format!("path_{}", hex::encode(&result[..8]))
}

fn apply_path_mode(path: &Path, mode: PathMode) -> String {
    match mode {
        PathMode::Relative => {
            // Store relative to workspace root
            path.strip_prefix(&workspace_root)
                .map(|p| p.display().to_string())
                .unwrap_or_else(|_| path.display().to_string())
        }
        PathMode::Basename => {
            // Filename only
            path.file_name()
                .map(|n| n.to_string_lossy().to_string())
                .unwrap_or_default()
        }
        PathMode::Full => {
            // Full path (with warning)
            path.display().to_string()
        }
        PathMode::Hash => {
            // Opaque hash
            hash_path(path)
        }
    }
}
