## Redaction Pipeline
```rust
pub fn apply_redactions(
    content: &str,
    config: &RedactionConfig,
    custom_patterns: &[Regex],
    allowlist: &HashSet<String>,
) -> RedactionResult {
    let mut result = content.to_string();
    let mut redactions = Vec::new();

    // 1. Apply built-in secret patterns
    if config.redact_secrets {
        for pattern in SECRET_PATTERNS {
            let regex = Regex::new(pattern.regex).unwrap();
            for mat in regex.find_iter(&result) {
                let matched = mat.as_str();
                if !allowlist.contains(matched) {
                    redactions.push(Redaction {
                        original: matched.to_string(),
                        reason: pattern.name.to_string(),
                        confidence: pattern.confidence,
                    });
                }
            }
            result = regex.replace_all(&result, config.replacement).to_string();
        }
    }

    // 2. Apply entropy-based detection
    if let Some(threshold) = config.entropy_threshold {
        let entropy_matches = detect_high_entropy_secrets(&result, threshold);
        for mat in entropy_matches {
            if !allowlist.contains(&mat.text) {
                result = result.replace(&mat.text, &config.replacement);
                redactions.push(Redaction {
                    original: mat.text,
                    reason: format!("High entropy ({:.2})", mat.entropy),
                    confidence: 0.6,
                });
            }
        }
    }

    // 3. Apply username/hostname redaction
    if config.redact_usernames {
        for um in detect_usernames(&result) {
            result = result.replace(&um.full_match, &um.full_match.replace(&um.username, "[USER]"));
        }
    }

    if config.redact_hostnames {
        for hm in detect_hostnames(&result) {
            result = result.replace(&hm.hostname, "[HOST]");
        }
    }

    // 4. Apply custom patterns
    for pattern in custom_patterns {
        result = pattern.replace_all(&result, &config.replacement).to_string();
    }

    RedactionResult {
        content: result,
        redactions,
    }
}
```

